class Solution:
    def longestMonotonicSubarray(self, nums: List[int]) -> int:
        if not nums:
            return 0

        max_len = 1
        current_incr = 1
        current_decr = 1

        for i in range(1, len(nums)):
            if nums[i] > nums[i - 1]:
                current_incr = current_incr + 1
                current_decr = 1
            elif nums[i] < nums[i - 1]:
                current_decr = current_decr + 1
                current_incr = 1
            else:
                current_incr = 1
                current_decr = 1

            max_len = max(max_len, current_incr, current_decr)

        return max_len
